import React, { useEffect, useState } from 'react';

const styles = {
  container: {
    position: 'fixed',
    inset: 0,
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',
    background: 'radial-gradient(ellipse at center, #1a0a2e 0%, #0d0015 50%, #000 100%)',
    zIndex: 100,
    transition: 'opacity 1s ease',
  },
  stars: {
    position: 'absolute',
    inset: 0,
    overflow: 'hidden',
    pointerEvents: 'none',
  },
  title: {
    fontFamily: "'Playfair Display', serif",
    fontSize: 'clamp(2rem, 6vw, 4.5rem)',
    color: '#fff',
    textAlign: 'center',
    fontStyle: 'italic',
    textShadow: '0 0 40px rgba(255,150,200,0.8), 0 0 80px rgba(255,100,180,0.4)',
    lineHeight: 1.2,
    marginBottom: '0.5rem',
    animation: 'fadeInUp 1.2s ease forwards',
    opacity: 0,
  },
  name: {
    fontFamily: "'Playfair Display', serif",
    fontSize: 'clamp(2.5rem, 8vw, 6rem)',
    color: '#ff85c0',
    textAlign: 'center',
    fontWeight: 700,
    textShadow: '0 0 30px rgba(255,130,180,1), 0 0 60px rgba(255,80,150,0.6)',
    marginBottom: '2rem',
    animation: 'fadeInUp 1.2s ease 0.3s forwards',
    opacity: 0,
  },
  subtitle: {
    fontFamily: "'Lato', sans-serif",
    fontSize: 'clamp(1rem, 2.5vw, 1.4rem)',
    color: 'rgba(255,200,230,0.8)',
    textAlign: 'center',
    fontWeight: 300,
    letterSpacing: '0.15em',
    marginBottom: '3rem',
    animation: 'fadeInUp 1.2s ease 0.6s forwards',
    opacity: 0,
  },
  button: {
    fontFamily: "'Lato', sans-serif",
    fontSize: '1.1rem',
    letterSpacing: '0.2em',
    fontWeight: 400,
    color: '#fff',
    background: 'transparent',
    border: '1px solid rgba(255,130,180,0.6)',
    padding: '1rem 3rem',
    cursor: 'pointer',
    borderRadius: '50px',
    position: 'relative',
    overflow: 'hidden',
    transition: 'all 0.4s ease',
    textTransform: 'uppercase',
    animation: 'fadeInUp 1.2s ease 0.9s forwards',
    opacity: 0,
    boxShadow: '0 0 20px rgba(255,130,180,0.2), inset 0 0 20px rgba(255,130,180,0.05)',
  },
  heart: {
    fontSize: '3rem',
    animation: 'heartbeat 1.5s ease infinite',
    display: 'block',
    marginBottom: '2rem',
    filter: 'drop-shadow(0 0 20px rgba(255,100,150,0.8))',
  },
};

const css = `
@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(30px); }
  to { opacity: 1; transform: translateY(0); }
}
@keyframes heartbeat {
  0%, 100% { transform: scale(1); }
  50% { transform: scale(1.15); }
}
@keyframes twinkle {
  0%, 100% { opacity: 0.3; transform: scale(0.8); }
  50% { opacity: 1; transform: scale(1.2); }
}
.btn-glow:hover {
  background: rgba(255,130,180,0.15) !important;
  box-shadow: 0 0 40px rgba(255,130,180,0.5), inset 0 0 40px rgba(255,130,180,0.1) !important;
  transform: scale(1.05);
  border-color: rgba(255,130,180,1) !important;
}
`;

// ===== KUSTOMISASI DI SINI =====
const NAMA_PACAR = "Sayang"; // Ganti dengan nama pacar kamu
const PESAN_PEMBUKA = "Ada kejutan spesial"; // Pesan di atas nama
const PESAN_SUB = "untukmu hari ini..."; // Pesan di bawah nama
// ================================

function generateStars(count) {
  return Array.from({ length: count }, (_, i) => ({
    id: i,
    x: Math.random() * 100,
    y: Math.random() * 100,
    size: Math.random() * 3 + 1,
    delay: Math.random() * 4,
    duration: Math.random() * 3 + 2,
  }));
}

export default function LandingPage({ onStart, fadeOut }) {
  const [stars] = useState(() => generateStars(120));

  return (
    <>
      <style>{css}</style>
      <div style={{ ...styles.container, opacity: fadeOut ? 0 : 1 }}>
        {/* Stars Background */}
        <div style={styles.stars}>
          {stars.map(star => (
            <div
              key={star.id}
              style={{
                position: 'absolute',
                left: `${star.x}%`,
                top: `${star.y}%`,
                width: `${star.size}px`,
                height: `${star.size}px`,
                borderRadius: '50%',
                background: `rgba(255, ${180 + Math.random() * 75}, ${200 + Math.random() * 55}, 0.9)`,
                animation: `twinkle ${star.duration}s ease ${star.delay}s infinite`,
              }}
            />
          ))}
        </div>

        {/* Content */}
        <span style={styles.heart}>💖</span>
        <h2 style={styles.title}>{PESAN_PEMBUKA}</h2>
        <h1 style={styles.name}>{NAMA_PACAR}</h1>
        <p style={styles.subtitle}>{PESAN_SUB}</p>
        <button
          className="btn-glow"
          style={styles.button}
          onClick={onStart}
        >
          ✨ Buka Kejutan
        </button>
      </div>
    </>
  );
}
